const O_WRONLY = 1;
const O_RDWR = 2;
const SEEK_SET = 0;
const SEEK_CUR = 1;
const SEEK_END = 2;

const ENOENT = 2;
const EBADF = 9;
const EACCES = 13;
const EEXIST = 17;
const EISDIR = 21;
const EINVAL = 22;
