const SYS_WRITE = 1;
const SYS_OPEN = 2;
const SYS_CLOSE = 3;
const SYS_LSEEK = 8;
const SYS_EXIT = 60;
const SYS_FSYNC = 74;
const SYS_RENAME = 82;
const SYS_MKDIR = 83;
const SYS_UNLINK = 87;
const SYS_TIME = 201;

const FPR_BITS_SCRATCH = new ArrayBuffer(8);
const FPR_BITS_VIEW = new DataView(FPR_BITS_SCRATCH);

function u32(x) {
  return x >>> 0;
}

function s32(x) {
  return x | 0;
}

function signExt16(x) {
  return (x << 16) >> 16;
}

function signExt8(x) {
  return (x << 24) >> 24;
}

function signExt64From32(x) {
