}

function zeroExt64From32(x) {
  return BigInt(u32(x));
}

function f32ToBits(v) {
  FPR_BITS_VIEW.setFloat32(0, Math.fround(v), true);
  return FPR_BITS_VIEW.getUint32(0, true);
}

function bitsToF32(bits) {
  FPR_BITS_VIEW.setUint32(0, u32(bits), true);
  return FPR_BITS_VIEW.getFloat32(0, true);
}

function f64ToBits(v) {
  FPR_BITS_VIEW.setFloat64(0, v, true);
  return [FPR_BITS_VIEW.getUint32(0, true), FPR_BITS_VIEW.getUint32(4, true)];
}

function bitsToF64(lo, hi) {
  FPR_BITS_VIEW.setUint32(0, u32(lo), true);
  FPR_BITS_VIEW.setUint32(4, u32(hi), true);
  return FPR_BITS_VIEW.getFloat64(0, true);
