class Memory {
  constructor() {
    this.pages = new Map();
    this.lastPageNum = -1;
    this.lastPage = null;
  }

  _getPage(pageNum, create) {
    if (pageNum === this.lastPageNum && this.lastPage) {
      return this.lastPage;
    }
    let page = this.pages.get(pageNum);
    if (!page && create) {
      page = Buffer.alloc(PAGE_SIZE);
      this.pages.set(pageNum, page);
    }
    this.lastPageNum = pageNum;
    this.lastPage = page || null;
    return page || null;
  }

  mapBytes(addr, bytes) {
    let base = u32(addr);
    for (let i = 0; i < bytes.length; i++) {
      this.write8(base + i, bytes[i]);
    }
  }

  read8(addr) {
    const a = u32(addr);
    const page = this._getPage(a >>> PAGE_BITS, false);
    if (!page) {
      return 0;
    }
    return page[a & PAGE_MASK];
  }

  write8(addr, value) {
    const a = u32(addr);
    const page = this._getPage(a >>> PAGE_BITS, true);
    page[a & PAGE_MASK] = value & 0xff;
  }

  read16(addr) {
    const a = u32(addr);
    return this.read8(a) | (this.read8(a + 1) << 8);
  }

  write16(addr, value) {
    const a = u32(addr);
    const v = value & 0xffff;
    this.write8(a, v & 0xff);
    this.write8(a + 1, (v >>> 8) & 0xff);
  }

  read32(addr) {
    const a = u32(addr);
    return u32(
      this.read8(a) |
      (this.read8(a + 1) << 8) |
      (this.read8(a + 2) << 16) |
      (this.read8(a + 3) << 24)
    );
  }

  write32(addr, value) {
    const a = u32(addr);
    const v = u32(value);
    this.write8(a, v & 0xff);
    this.write8(a + 1, (v >>> 8) & 0xff);
    this.write8(a + 2, (v >>> 16) & 0xff);
    this.write8(a + 3, (v >>> 24) & 0xff);
  }

  read64(addr) {
    const lo = this.read32(addr);
    const hi = this.read32(u32(addr + 4));
    return [lo, hi];
  }

  write64(addr, lo, hi) {
    this.write32(addr, lo);
    this.write32(u32(addr + 4), hi);
  }

  readBytes(addr, len) {
    const out = Buffer.alloc(len);
    let a = u32(addr);
    for (let i = 0; i < len; i++) {
      out[i] = this.read8(a + i);
    }
    return out;
  }

  writeBytes(addr, buf) {
    let a = u32(addr);
    for (let i = 0; i < buf.length; i++) {
      this.write8(a + i, buf[i]);
    }
  }

  readCString(addr, maxLen = 4096) {
    let a = u32(addr);
    const out = [];
    for (let i = 0; i < maxLen; i++) {
      const b = this.read8(a + i);
      if (b === 0) {
        break;
      }
      out.push(b);
    }
    return Buffer.from(out).toString('utf8');
  }
}

