function loadELF(filePath, memory) {
  const elf = fs.readFileSync(filePath);
  if (elf.readUInt32BE(0) !== 0x7f454c46) {
    throw new Error('not an ELF file');
  }
  const eiClass = elf[4];
  const eiData = elf[5];
  if (eiClass !== 1 || eiData !== 1) {
    throw new Error('expected ELF32 little-endian');
  }

  const eMachine = elf.readUInt16LE(18);
  if (eMachine !== 8) {
    throw new Error(`expected MIPS machine (8), got ${eMachine}`);
  }

  const eEntry = elf.readUInt32LE(24);
  const ePhoff = elf.readUInt32LE(28);
  const ePhentsize = elf.readUInt16LE(42);
  const ePhnum = elf.readUInt16LE(44);

  for (let i = 0; i < ePhnum; i++) {
    const off = ePhoff + i * ePhentsize;
    const pType = elf.readUInt32LE(off + 0);
    const pOffset = elf.readUInt32LE(off + 4);
    const pVaddr = elf.readUInt32LE(off + 8);
    const pFilesz = elf.readUInt32LE(off + 16);
    if (pType !== 1 || pFilesz === 0) {
      continue;
    }
    const bytes = elf.subarray(pOffset, pOffset + pFilesz);
    memory.mapBytes(pVaddr, bytes);
  }

  return { entry: eEntry };
}

function parseArgs(argv) {
  const args = {
    elfPath: path.join(__dirname, 'doomgeneric_mips'),
    maxFrames: 1,
    progress: false,
    maxSteps: 2_000_000_000,
  };

  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === '--frames') {
      args.maxFrames = Number(argv[++i]);
    } else if (a === '--progress') {
      args.progress = true;
    } else if (a === '--max-steps') {
      args.maxSteps = Number(argv[++i]);
    } else if (a === '--help' || a === '-h') {
      process.stdout.write(
        'Usage: node vm.js [elf_path] [--frames N] [--progress] [--max-steps N]\n' +
        '  --frames N     Stop after N completed /tmp/frame.bmp writes (0 = run forever). Default: 1\n' +
        '  --progress     Print periodic execution progress.\n' +
        '  --max-steps N  Instruction limit safety guard.\n'
      );
      process.exit(0);
    } else if (!a.startsWith('--')) {
      args.elfPath = path.resolve(a);
    } else {
      throw new Error(`unknown argument: ${a}`);
    }
  }

  if (!Number.isFinite(args.maxFrames) || args.maxFrames < 0) {
    throw new Error('--frames must be >= 0');
  }
  if (!Number.isFinite(args.maxSteps) || args.maxSteps <= 0) {
    throw new Error('--max-steps must be > 0');
  }

  args.maxFrames = Math.floor(args.maxFrames);
  args.maxSteps = Math.floor(args.maxSteps);
  return args;
}

function main() {
  const opts = parseArgs(process.argv.slice(2));
  const mem = new Memory();
  const { entry } = loadELF(opts.elfPath, mem);
  const vm = new MipsVM(mem, entry, {
    cwd: process.cwd(),
    maxFrames: opts.maxFrames,
    progress: opts.progress,
  });

  process.stdout.write(`loaded ${opts.elfPath}, entry=0x${entry.toString(16)}\n`);
  vm.run(opts.maxSteps);
  process.stdout.write(`halted after ${vm.steps} instructions, exit=${vm.exitCode}\n`);
  process.exit(vm.exitCode | 0);
}

main();
