}

function bitsToF64(lo, hi) {
  FPR_BITS_VIEW.setUint32(0, u32(lo), true);
  FPR_BITS_VIEW.setUint32(4, u32(hi), true);
  return FPR_BITS_VIEW.getFloat64(0, true);
}

class Memory {
  constructor() {
    this.pages = new Map();
    this.lastPageNum = -1;
    this.lastPage = null;
  }

  _getPage(pageNum, create) {
    if (pageNum === this.lastPageNum && this.lastPage) {
      return this.lastPage;
    }
    let page = this.pages.get(pageNum);
    if (!page && create) {
      page = Buffer.alloc(PAGE_SIZE);
      this.pages.set(pageNum, page);
    }
    this.lastPageNum = pageNum;
    this.lastPage = page || null;
    return page || null;
  }

  mapBytes(addr, bytes) {
    let base = u32(addr);
    for (let i = 0; i < bytes.length; i++) {
      this.write8(base + i, bytes[i]);
    }
  }

  read8(addr) {
    const a = u32(addr);
    const page = this._getPage(a >>> PAGE_BITS, false);
    if (!page) {
      return 0;
    }
    return page[a & PAGE_MASK];
  }

  write8(addr, value) {
    const a = u32(addr);
    const page = this._getPage(a >>> PAGE_BITS, true);
    page[a & PAGE_MASK] = value & 0xff;
  }

  read16(addr) {
    const a = u32(addr);
    return this.read8(a) | (this.read8(a + 1) << 8);
  }

  write16(addr, value) {
    const a = u32(addr);
    const v = value & 0xffff;
    this.write8(a, v & 0xff);
    this.write8(a + 1, (v >>> 8) & 0xff);
  }

  read32(addr) {
    const a = u32(addr);
    return u32(
      this.read8(a) |
      (this.read8(a + 1) << 8) |
      (this.read8(a + 2) << 16) |
      (this.read8(a + 3) << 24)
    );
  }

  write32(addr, value) {
    const a = u32(addr);
    const v = u32(value);
    this.write8(a, v & 0xff);
    this.write8(a + 1, (v >>> 8) & 0xff);
    this.write8(a + 2, (v >>> 16) & 0xff);
    this.write8(a + 3, (v >>> 24) & 0xff);
  }

  read64(addr) {
    const lo = this.read32(addr);
    const hi = this.read32(u32(addr + 4));
    return [lo, hi];
  }

  write64(addr, lo, hi) {
    this.write32(addr, lo);
    this.write32(u32(addr + 4), hi);
  }

  readBytes(addr, len) {
    const out = Buffer.alloc(len);
    let a = u32(addr);
    for (let i = 0; i < len; i++) {
      out[i] = this.read8(a + i);
    }
    return out;
  }

  writeBytes(addr, buf) {
    let a = u32(addr);
    for (let i = 0; i < buf.length; i++) {
      this.write8(a + i, buf[i]);
    }
  }

  readCString(addr, maxLen = 4096) {
    let a = u32(addr);
    const out = [];
    for (let i = 0; i < maxLen; i++) {
      const b = this.read8(a + i);
      if (b === 0) {
        break;
      }
      out.push(b);
    }
    return Buffer.from(out).toString('utf8');
  }
}

class SyscallLayer {
  constructor(vm, opts) {
    this.vm = vm;
    this.cwd = opts.cwd;
    this.framePath = '/tmp/frame.bmp';
    this.frameDir = path.join(this.cwd, 'frames');
    this.frameCounter = 0;
    this.maxFrames = opts.maxFrames;
    this.fdTable = new Map();
    this.nextFd = 3;

    try {
      fs.mkdirSync(this.frameDir, { recursive: true });
    } catch {
      // ignore
    }
  }

  _resolvePath(raw) {
    if (!raw) return '';
    if (path.isAbsolute(raw)) return raw;
    return path.join(this.cwd, raw);
  }

  _allocFd(entry) {
    while (this.fdTable.has(this.nextFd)) {
      this.nextFd++;
    }
    const fd = this.nextFd;
    this.fdTable.set(fd, entry);
    this.nextFd++;
    return fd;
  }

  _errnoFromNode(err) {
    switch (err && err.code) {
      case 'ENOENT': return ENOENT;
      case 'EACCES': return EACCES;
      case 'EEXIST': return EEXIST;
      case 'EISDIR': return EISDIR;
      case 'EBADF': return EBADF;
      case 'EINVAL': return EINVAL;
      default: return EINVAL;
    }
  }

  _storeFrameSnapshot() {
    this.frameCounter += 1;
    const outName = `frame_${String(this.frameCounter).padStart(6, '0')}.bmp`;
    const outPath = path.join(this.frameDir, outName);
    try {
      fs.copyFileSync(this.framePath, outPath);
      process.stdout.write(`saved ${outPath}\n`);
    } catch (err) {
      process.stderr.write(`failed to copy frame: ${err.message}\n`);
    }
    if (this.maxFrames > 0 && this.frameCounter >= this.maxFrames) {
      this.vm.halted = true;
      this.vm.exitCode = 0;
    }
  }

  handle(sysno, a0, a1, a2, a3, a4, a5) {
    try {
      switch (sysno) {
        case SYS_READ: {
          const fd = s32(a0);
          const bufPtr = u32(a1);
          const count = u32(a2);
          if (count === 0) return 0;
          if (fd === 0) {
            return 0;
          }
          const ent = this.fdTable.get(fd);
          if (!ent) return -EBADF;
          const buf = Buffer.alloc(count);
          const n = fs.readSync(ent.hostFd, buf, 0, count, ent.offset);
          if (n > 0) {
            this.vm.mem.writeBytes(bufPtr, buf.subarray(0, n));
            ent.offset += n;
          }
          return n;
        }
        case SYS_WRITE: {
          const fd = s32(a0);
          const bufPtr = u32(a1);
          const count = u32(a2);
          if (count === 0) return 0;
          const data = this.vm.mem.readBytes(bufPtr, count);
          if (fd === 1 || fd === 0) {
            fs.writeSync(process.stdout.fd, data);
            return count;
          }
          if (fd === 2) {
            fs.writeSync(process.stderr.fd, data);
            return count;
          }
          const ent = this.fdTable.get(fd);
          if (!ent) return -EBADF;
          const n = fs.writeSync(ent.hostFd, data, 0, count, ent.offset);
          ent.offset += n;
          ent.wrote = ent.wrote || n > 0;
          return n;
        }
        case SYS_OPEN: {
          const pathPtr = u32(a0);
          const flags = s32(a1);
          const mode = u32(a2);
          const rawPath = this.vm.mem.readCString(pathPtr);
          const realPath = this._resolvePath(rawPath);
          const hostFd = fs.openSync(realPath, flags, mode);
          let initialOffset = 0;
          if ((flags & 1024) !== 0) {
            initialOffset = fs.fstatSync(hostFd).size;
          }
          const vmFd = this._allocFd({
            hostFd,
            offset: initialOffset,
            path: realPath,
            wrote: false,
            isFrame: realPath === this.framePath,
          });
          return vmFd;
        }
        case SYS_CLOSE: {
          const fd = s32(a0);
          const ent = this.fdTable.get(fd);
          if (!ent) return -EBADF;
          fs.closeSync(ent.hostFd);
          this.fdTable.delete(fd);
          if (ent.isFrame && ent.wrote) {
            this._storeFrameSnapshot();
          }
          return 0;
        }
        case SYS_LSEEK: {
          const fd = s32(a0);
          const off = s32(a1);
          const whence = s32(a2);
          const ent = this.fdTable.get(fd);
          if (!ent) return -EBADF;
          let next;
          if (whence === SEEK_SET) {
            next = off;
          } else if (whence === SEEK_CUR) {
            next = ent.offset + off;
          } else if (whence === SEEK_END) {
            const sz = fs.fstatSync(ent.hostFd).size;
            next = sz + off;
          } else {
            return -EINVAL;
          }
          if (next < 0) return -EINVAL;
          ent.offset = next;
          return next | 0;
        }
        case SYS_FSYNC: {
          const fd = s32(a0);
          const ent = this.fdTable.get(fd);
          if (!ent) return -EBADF;
          fs.fsyncSync(ent.hostFd);
          return 0;
        }
        case SYS_RENAME: {
          const oldPath = this._resolvePath(this.vm.mem.readCString(u32(a0)));
          const newPath = this._resolvePath(this.vm.mem.readCString(u32(a1)));
          fs.renameSync(oldPath, newPath);
          return 0;
        }
        case SYS_MKDIR: {
          const p = this._resolvePath(this.vm.mem.readCString(u32(a0)));
          const mode = u32(a1);
          fs.mkdirSync(p, { mode });
          return 0;
        }
        case SYS_UNLINK: {
          const p = this._resolvePath(this.vm.mem.readCString(u32(a0)));
          fs.unlinkSync(p);
          return 0;
        }
        case SYS_TIME: {
          const outPtr = u32(a0);
          const now = Math.floor(Date.now() / 1000) | 0;
          if (outPtr !== 0) {
            this.vm.mem.write32(outPtr, now);
          }
          return now;
        }
        case SYS_EXIT: {
          this.vm.halted = true;
          this.vm.exitCode = s32(a0);
          return 0;
        }
        default: {
          process.stderr.write(`unhandled syscall ${sysno}(${a0},${a1},${a2},${a3},${a4},${a5})\n`);
          return -ENOSYS;
        }
      }
    } catch (err) {
      return -this._errnoFromNode(err);
    }
  }
}

class MipsVM {
  constructor(memory, entryPoint, opts) {
    this.mem = memory;
    this.regs = new Uint32Array(32);
    this.fprLo = new Uint32Array(32);
    this.fprHi = new Uint32Array(32);
    this.fcc0 = false;
    this.hi = 0;
    this.lo = 0;
    this.pc = u32(entryPoint);
    this.halted = false;
    this.exitCode = 0;
    this.steps = 0;
    this.startMs = Date.now();
    this.lastReportMs = this.startMs;
    this.lastReportSteps = 0;
    this.progress = Boolean(opts.progress);

    this.regs[29] = 0x7fff0000; // $sp
    this.sys = new SyscallLayer(this, {
      cwd: opts.cwd,
      maxFrames: opts.maxFrames,
    });
  }

  setReg(idx, val) {
    if (idx !== 0) {
      this.regs[idx] = u32(val);
    }
  }

  getF64(idx) {
    return bitsToF64(this.fprLo[idx], this.fprHi[idx]);
  }

  setF64(idx, val) {
    const [lo, hi] = f64ToBits(val);
    this.fprLo[idx] = lo;
    this.fprHi[idx] = hi;
  }

  getF32(idx) {
    return bitsToF32(this.fprLo[idx]);
  }

  setF32(idx, val) {
    this.fprLo[idx] = f32ToBits(val);
  }

  executeInstruction(pc, instr, inDelaySlot) {
    const op = instr >>> 26;
    const rs = (instr >>> 21) & 0x1f;
    const rt = (instr >>> 16) & 0x1f;
    const rd = (instr >>> 11) & 0x1f;
    const sa = (instr >>> 6) & 0x1f;
    const funct = instr & 0x3f;
    const imm = instr & 0xffff;
    const simm = signExt16(imm);

    switch (op) {
      case 0x00: {
        switch (funct) {
          case 0x00: // sll
            this.setReg(rd, this.regs[rt] << sa);
            return null;
          case 0x02: { // srl/rotr
            if (rs === 1) {
              const v = this.regs[rt];
              this.setReg(rd, (v >>> sa) | (v << (32 - sa)));
            } else {
              this.setReg(rd, this.regs[rt] >>> sa);
            }
            return null;
          }
          case 0x03: // sra
            this.setReg(rd, s32(this.regs[rt]) >> sa);
            return null;
          case 0x04: // sllv
            this.setReg(rd, this.regs[rt] << (this.regs[rs] & 31));
            return null;
          case 0x06: // srlv
            this.setReg(rd, this.regs[rt] >>> (this.regs[rs] & 31));
            return null;
          case 0x07: // srav
            this.setReg(rd, s32(this.regs[rt]) >> (this.regs[rs] & 31));
            return null;
          case 0x08: { // jr
            const target = this.regs[rs];
            return { taken: true, target };
          }
          case 0x09: { // jalr
            const target = this.regs[rs];
            const link = u32(pc + 8);
            this.setReg(rd === 0 ? 31 : rd, link);
            return { taken: true, target };
          }
          case 0x0a: // movz
            if (this.regs[rt] === 0) this.setReg(rd, this.regs[rs]);
            return null;
          case 0x0b: // movn
            if (this.regs[rt] !== 0) this.setReg(rd, this.regs[rs]);
            return null;
          case 0x0c: { // syscall
            const ret = this.sys.handle(
              this.regs[2] | 0,
              this.regs[4],
              this.regs[5],
              this.regs[6],
              this.regs[7],
              this.regs[8],
              this.regs[9]
            );
            this.setReg(2, ret);
            return null;
          }
          case 0x10: // mfhi
            this.setReg(rd, this.hi);
            return null;
          case 0x12: // mflo
            this.setReg(rd, this.lo);
            return null;
          case 0x18: { // mult
            const prod = signExt64From32(this.regs[rs]) * signExt64From32(this.regs[rt]);
            this.lo = Number(prod & 0xffffffffn) >>> 0;
            this.hi = Number((prod >> 32n) & 0xffffffffn) >>> 0;
            return null;
          }
          case 0x19: { // multu
            const prod = zeroExt64From32(this.regs[rs]) * zeroExt64From32(this.regs[rt]);
            this.lo = Number(prod & 0xffffffffn) >>> 0;
            this.hi = Number((prod >> 32n) & 0xffffffffn) >>> 0;
            return null;
          }
          case 0x1a: { // div
            const num = s32(this.regs[rs]);
            const den = s32(this.regs[rt]);
            if (den !== 0) {
              this.lo = u32(Math.trunc(num / den));
              this.hi = u32(num % den);
            }
            return null;
          }
          case 0x1b: { // divu
            const num = this.regs[rs] >>> 0;
            const den = this.regs[rt] >>> 0;
            if (den !== 0) {
              this.lo = u32(Math.trunc(num / den));
              this.hi = u32(num % den);
            }
            return null;
          }
          case 0x21: // addu
            this.setReg(rd, this.regs[rs] + this.regs[rt]);
            return null;
          case 0x23: // subu
            this.setReg(rd, this.regs[rs] - this.regs[rt]);
            return null;
          case 0x24: // and
            this.setReg(rd, this.regs[rs] & this.regs[rt]);
            return null;
          case 0x25: // or
            this.setReg(rd, this.regs[rs] | this.regs[rt]);
            return null;
          case 0x26: // xor
            this.setReg(rd, this.regs[rs] ^ this.regs[rt]);
            return null;
          case 0x27: // nor
            this.setReg(rd, ~(this.regs[rs] | this.regs[rt]));
            return null;
          case 0x2a: // slt
            this.setReg(rd, s32(this.regs[rs]) < s32(this.regs[rt]) ? 1 : 0);
            return null;
          case 0x2b: // sltu
            this.setReg(rd, this.regs[rs] < this.regs[rt] ? 1 : 0);
            return null;
          case 0x34: // teq
            if (this.regs[rs] === this.regs[rt]) {
              throw new Error(`TEQ trap at 0x${pc.toString(16)}`);
            }
            return null;
          default:
            throw new Error(`Unsupported SPECIAL funct 0x${funct.toString(16)} at 0x${pc.toString(16)}`);
        }
      }
      case 0x01: { // regimm
        const target = u32(pc + 4 + ((simm << 2) | 0));
        if (rt === 0x00) {
          return { taken: s32(this.regs[rs]) < 0, target };
        }
        if (rt === 0x01) {
          return { taken: s32(this.regs[rs]) >= 0, target };
        }
        throw new Error(`Unsupported REGIMM rt ${rt} at 0x${pc.toString(16)}`);
      }
      case 0x02: { // j
        const target = u32(((pc + 4) & 0xf0000000) | ((instr & 0x03ffffff) << 2));
        return { taken: true, target };
      }
      case 0x03: { // jal
        const target = u32(((pc + 4) & 0xf0000000) | ((instr & 0x03ffffff) << 2));
        this.setReg(31, u32(pc + 8));
        return { taken: true, target };
      }
      case 0x04: { // beq
        const target = u32(pc + 4 + ((simm << 2) | 0));
        return { taken: this.regs[rs] === this.regs[rt], target };
      }
      case 0x05: { // bne
        const target = u32(pc + 4 + ((simm << 2) | 0));
        return { taken: this.regs[rs] !== this.regs[rt], target };
      }
      case 0x06: { // blez
        const target = u32(pc + 4 + ((simm << 2) | 0));
        return { taken: s32(this.regs[rs]) <= 0, target };
      }
      case 0x07: { // bgtz
        const target = u32(pc + 4 + ((simm << 2) | 0));
        return { taken: s32(this.regs[rs]) > 0, target };
      }
      case 0x09: // addiu
        this.setReg(rt, this.regs[rs] + simm);
        return null;
      case 0x0a: // slti
        this.setReg(rt, s32(this.regs[rs]) < simm ? 1 : 0);
        return null;
      case 0x0b: // sltiu
        this.setReg(rt, this.regs[rs] < u32(simm) ? 1 : 0);
        return null;
      case 0x0c: // andi
        this.setReg(rt, this.regs[rs] & imm);
        return null;
      case 0x0d: // ori
        this.setReg(rt, this.regs[rs] | imm);
        return null;
      case 0x0e: // xori
        this.setReg(rt, this.regs[rs] ^ imm);
        return null;
      case 0x0f: // lui
        this.setReg(rt, imm << 16);
        return null;
      case 0x11: { // COP1
        const fmt = rs;
        if (fmt === 0x00) { // mfc1
          this.setReg(rt, this.fprLo[rd]);
          return null;
        }
        if (fmt === 0x04) { // mtc1
          this.fprLo[rd] = this.regs[rt];
          return null;
        }
        if (fmt === 0x07) { // mthc1
          this.fprHi[rd] = this.regs[rt];
          return null;
        }
        if (fmt === 0x08) { // bc1*
          const ccBranch = rt;
          const target = u32(pc + 4 + ((simm << 2) | 0));
          if (ccBranch === 0x01) { // bc1t
            return { taken: this.fcc0, target };
          }
          throw new Error(`Unsupported BC1 rt=0x${ccBranch.toString(16)} at 0x${pc.toString(16)}`);
        }

        const ft = rt;
        const fs = rd;
        const fd = sa;

        if (fmt === 0x10) { // single
          switch (funct) {
            case 0x00: // add.s
              this.setF32(fd, this.getF32(fs) + this.getF32(ft));
              return null;
            case 0x02: // mul.s
              this.setF32(fd, this.getF32(fs) * this.getF32(ft));
              return null;
            case 0x03: // div.s
              this.setF32(fd, this.getF32(fs) / this.getF32(ft));
              return null;
            case 0x06: // mov.s
              this.fprLo[fd] = this.fprLo[fs];
              return null;
            case 0x07: // neg.s
              this.setF32(fd, -this.getF32(fs));
              return null;
            case 0x0d: { // trunc.w.s
              const v = this.getF32(fs);
              this.fprLo[fd] = u32(Math.trunc(v));
              return null;
            }
            case 0x11: // movt.s
              if (this.fcc0) this.fprLo[fd] = this.fprLo[fs];
              return null;
            case 0x21: // cvt.d.s
              this.setF64(fd, this.getF32(fs));
              return null;
            case 0x34: { // c.olt.s
              const a = this.getF32(fs);
              const b = this.getF32(ft);
              this.fcc0 = Number.isFinite(a) && Number.isFinite(b) && a < b;
              return null;
            }
            default:
              throw new Error(`Unsupported COP1.S funct 0x${funct.toString(16)} at 0x${pc.toString(16)}`);
          }
        }

        if (fmt === 0x11) { // double
          switch (funct) {
            case 0x06: // mov.d
              this.fprLo[fd] = this.fprLo[fs];
              this.fprHi[fd] = this.fprHi[fs];
              return null;
            case 0x07: // neg.d
              this.setF64(fd, -this.getF64(fs));
              return null;
            case 0x11: // movt.d
              if (this.fcc0) {
                this.fprLo[fd] = this.fprLo[fs];
                this.fprHi[fd] = this.fprHi[fs];
              }
              return null;
            case 0x34: { // c.olt.d
              const a = this.getF64(fs);
              const b = this.getF64(ft);
              this.fcc0 = Number.isFinite(a) && Number.isFinite(b) && a < b;
              return null;
            }
            default:
              throw new Error(`Unsupported COP1.D funct 0x${funct.toString(16)} at 0x${pc.toString(16)}`);
          }
        }

        if (fmt === 0x14) { // word
          switch (funct) {
            case 0x20: { // cvt.s.w
              const v = s32(this.fprLo[fs]);
              this.setF32(fd, v);
              return null;
            }
            default:
              throw new Error(`Unsupported COP1.W funct 0x${funct.toString(16)} at 0x${pc.toString(16)}`);
          }
        }

        throw new Error(`Unsupported COP1 fmt ${fmt} at 0x${pc.toString(16)}`);
      }
      case 0x1c: { // SPECIAL2
        if (funct === 0x02) { // mul
          const prod = BigInt(s32(this.regs[rs])) * BigInt(s32(this.regs[rt]));
          this.setReg(rd, Number(prod & 0xffffffffn));
          return null;
        }
        throw new Error(`Unsupported SPECIAL2 funct 0x${funct.toString(16)} at 0x${pc.toString(16)}`);
      }
      case 0x1f: { // SPECIAL3
        switch (funct) {
          case 0x00: { // ext
            const pos = rd;
            const size = sa + 1;
            const mask = size >= 32 ? 0xffffffff : ((1 << size) - 1);
            this.setReg(rt, (this.regs[rs] >>> pos) & mask);
            return null;
          }
          case 0x04: { // ins
            const pos = rd;
            const size = sa - rd + 1;
            const rawMask = size >= 32 ? 0xffffffff : ((1 << size) - 1);
            const mask = u32(rawMask << pos);
            const src = u32((this.regs[rs] & rawMask) << pos);
            this.setReg(rt, (this.regs[rt] & ~mask) | src);
            return null;
          }
          case 0x20: { // wsbh
            const v = this.regs[rt];
            const out = ((v & 0x00ff00ff) << 8) | ((v & 0xff00ff00) >>> 8);
            this.setReg(rd, out);
            return null;
          }
          default:
            throw new Error(`Unsupported SPECIAL3 funct 0x${funct.toString(16)} at 0x${pc.toString(16)}`);
        }
      }
      case 0x20: { // lb
        const addr = u32(this.regs[rs] + simm);
        this.setReg(rt, signExt8(this.mem.read8(addr)));
        return null;
      }
      case 0x21: { // lh
